import {ParseResults} from 'jibo-common-types';

export type ParseResults = ParseResults;

declare type ParseCallback = (error:Error|string, result:ParseResults)=>void;
export default class NLUService {
    init(service:any, done:Function): void;
    compile(rule:string, callback:(error:string, uri:string)=>void, handle?:string):void;
    compile(rule:string, handle?:string):Promise<string>;
    parseFromRule(rule:string, rawText:string, callback:ParseCallback, messageId?:string):void;
    parseFromRule(rule:string, rawText:string, messageId?:string):Promise<ParseResults>;
    parseFromURI(ruleHandle:string, rawText:string, callback:ParseCallback, messageId?:string):void;
    parseFromURI(ruleHandle:string, rawText:string, messageId?:string):Promise<ParseResults>;
    union(uris:string[], callback:(error:string, uri:string)=>void, ruleHandle?:string):void;
    union(uris:string[], ruleHandle:string):Promise<string>;
    parseFromFile(fstUri:string, rawText:string, callback:ParseCallback, messageId?:string):void;
    parseFromFile(fstUri:string, rawText:string, messageId:string):Promise<ParseResults>;
    compileFromFst(fstFilePath:string, callback:(error:string, uri:string)=>void, handle?:string):void;
    compileFromFst(fstFilePath:string, handle?:string):Promise<string>;
    removeFromMemory(uri:string, callback:(error:string, uri:string)=>void)
    removeFromMemory(uri:string):Promise<string>;
    saveFstOnDisk(uri:string, filePath:string, callback:(error:string, uri:string)=>void):void;
    saveFstOnDisk(uri:string, filePath:string):Promise<string>;
    resetMemory(callback:(error:Error, result:any)=>void):void;
    resetMemory():Promise<any>;
    clearCache(uri?:string):void;
    recompileCachedRules(callback:(error:Error, result:any)=>void):void;
    recompileCachedRules():Promise<any>;
}
